pub fn cast_f(a: &mut State, mut b: Decision, _c: bool) -> (Decision, Option<String>) {
    // Reuse only when the subject is stable (epoch unchanged).
    let track = State::track_key(&b.subject, &b.object, &b.mode);
    let key = format!("{track}|{}", b.tick);

    let reused = a
        .seen
        .get(&key)
        .map(|old| old == &b.outcome)
        .unwrap_or(false);

    b.reused = reused;
    a.seen.insert(key, b.outcome.clone());

    // With correct mote_e semantics, we should not be producing "allow" for blocked
    // subjects via delegation. Keep stale empty.
    (b, None)
}
