pub fn phase_a(a: &mut State, b: &Event, c: &mut CaseReport) -> Result<(), String> {
    match b.kind.as_str() {
        "grant" => {
            let (object, mode) = b
                .right
                .split_once('/')
                .ok_or_else(|| format!("bad grant row {}", b.right))?;
            a.direct
                .insert((b.left.clone(), object.to_string(), mode.to_string()));
            a.clock += 1;
            Ok(())
        }
        "delegate" => {
            a.chain.insert(b.right.clone(), b.left.clone());
            a.clock += 1;
            Ok(())
        }
        "revoke" => fold_b(a, &b.left),
        "batch" => {
            a.group_active = b.left.clone();
            a.group_slot.clear();
            a.clock += 1;
            Ok(())
        }
        "end" => {
            a.group_active.clear();
            a.group_slot.clear();
            a.clock += 1;
            Ok(())
        }
        "check" => {
            // Advance the evaluation epoch. This guarantees nondecreasing epochs within a case,
            // while still being tied to the state at evaluation time.
            a.clock += 1;
            let epoch = a.clock;

            let (subject, object, mode) = split_subject_object_mode(&b.right)?;
            let row = if a.group_active.is_empty() {
                wrap_g(a, &b.left, &subject, &object, &mode, epoch)
            } else {
                lift_d(a, &b.left, &subject, &object, &mode, epoch)
            };
            let (row, note) = cast_f(a, row, true);
            c.decisions.push(row);
            if let Some(note) = note {
                c.stale.push(note);
            }
            Ok(())
        }
        other => Err(format!("unknown trace row {other}")),
    }
}

fn wrap_g(
    a: &mut State,
    label: &str,
    subject: &str,
    object: &str,
    mode: &str,
