        "revoke" => fold_b(a, &b.left),
        "batch" => {
            a.group_active = b.left.clone();
            a.group_slot.clear();
            Ok(())
        }
        "end" => {
            a.group_active.clear();
            a.group_slot.clear();
            Ok(())
        }
        "check" => {
            let (subject, object, mode) = split_subject_object_mode(&b.right)?;
            let row = if a.group_active.is_empty() {
