pub fn lift_d(a: &mut State, b: &str, c: &str, d: &str, e: &str, epoch: u64) -> Decision {
    let slot = State::slot_key(c, d, e);

    if let Some(outcome) = a.group_slot.get(&slot) {
        let via = if outcome == "allow" {
            mote_e(a, c, d, e).1
        } else {
            String::new()
        };
        let mut row = Decision::blank(b, c, d, e, epoch);
        row.outcome = outcome.clone();
        row.group = a.group_active.clone();
        row.via = via;
        return row;
    }

    let (outcome, via) = mote_e(a, c, d, e);
    a.group_slot.insert(slot, outcome.clone());
    let mut row = Decision::blank(b, c, d, e, epoch);
    row.outcome = outcome;
    row.group = a.group_active.clone();
    row.via = via;
    row
}
